using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr circle = sketchCircles->addByCenterRadius(centerPoint, 3.0);
    if (!circle)
        return false;

    // Get the profile defined by the circle.
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create an extrusion input
    Ptr feats = rootComp->features();
    if (!feats)
        return false;
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Define that the extent is a distance extent of 5 cm.
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;
    extInput->setDistanceExtent(false, distance);

    // Create the extrusion.
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the end face of the extrusion
    Ptr endFaces = ext->endFaces();
    if (!endFaces)
        return false;
    Ptr endFace = endFaces->item(0);
    if (!endFace)
        return false;

    // Create a construction plane by offsetting the end face
    Ptr planes = rootComp->constructionPlanes();
    if (!planes)
        return false;
    Ptr planeInput = planes->createInput();
    if (!planeInput)
        return false;
    Ptr offsetVal = ValueInput::createByString("2 cm");
    if (!offsetVal)
        return false;
    planeInput->setByOffset(endFace, offsetVal);
    Ptr offsetPlane = planes->add(planeInput);
    if (!offsetPlane)
        return false;

    // Create a sketch on the new construction plane and add four sketch points on it
    Ptr offsetSketch = sketches->add(offsetPlane);
    if (!offsetSketch)
        return false;
    Ptr offsetSketchPoints = offsetSketch->sketchPoints();
    if (!offsetSketchPoints)
        return false;
    Ptr p0 = Point3D::create(1, 0, 0);
    if (!p0)
        return false;
    Ptr sPt0 = offsetSketchPoints->add(p0);
    if (!sPt0)
        return false;
    Ptr p1 = Point3D::create(0, 1, 0);
    if (!p1)
        return false;
    Ptr sPt1 = offsetSketchPoints->add(p1);
    if (!sPt1)
        return false;
    Ptr p2 = Point3D::create(-1, 0, 0);
    if (!p2)
        return false;
    Ptr sPt2 = offsetSketchPoints->add(p2);
    if (!sPt2)
        return false;
    Ptr p3 = Point3D::create(0, -1, 0);
    if (!p3)
        return false;
    Ptr sPt3 = offsetSketchPoints->add(p3);
    if (!sPt3)
        return false;

    // Add the four sketch points into a collection
    Ptr ptColl = ObjectCollection::create();
    if (!ptColl)
        return false;
    ptColl->add(sPt0);
    ptColl->add(sPt1);
    ptColl->add(sPt2);
    ptColl->add(sPt3);

    // Create a hole input
    Ptr holes = feats->holeFeatures();
    if (!holes)
        return false;
    Ptr holeInput = holes->createSimpleInput(ValueInput::createByString("2 mm"));
    if (!holeInput)
        return false;
    holeInput->setPositionBySketchPoints(ptColl);
    holeInput->setDistanceExtent(distance);

    Ptr hole = holes->add(holeInput);
    if (!hole)
        return false;

    return true;
}
